115	  it("should apply -15% follow-up discount for contracts after the first", () => {
116	    const scenario = {
117	      customer: { name: "Test Customer", years: 0, contracts: 0 },
118	      steps: [
119	        { type: "quote", items: [{ type: "Sword" }] },
120	        { type: "quote", items: [{ type: "Sword" }] },
121	      ],
122	    };
123	    expect(processScenario(scenario)).toEqual({ results: [{ premium: 115 }, { premium: 100 }] });
124	  });
125	
126	  // Rounding
127	  it.todo("should round premium UP to a whole G");
128	
129	  // Claim: basic deductible
130	  it.todo("should subtract 100 G deductible per damaged item from a basic claim");
131	
132	  // Claim: payout cap
133	  it.todo("should cap total payout at 2x the policy insurance sum");
134	
135	  // Claim: high enchantment clause
136	  it.todo("should reimburse 50% of damage when item has enchantment >= 8 (then deductible)");
137	
138	  // Claim: dragon material clause
139	  it.todo("should reimburse full damage when item is made of dragon material");
140	
141	  // Claim: both clauses combined
142	  it.todo("should apply 50% rule first then deductible when both high-enchantment and dragon material apply");
143	
144	  // Claim: rounding
145	  it.todo("should round payouts DOWN to a whole G");
146	
147	  // CLI errors (basic validation)
148	  it.todo("should error on unknown item type in a quote");
149	  it.todo("should error on a claim damages array that does not match policy items");
150	  it.todo("should error on negative damage amount in a claim");
151	});
